class Solution:
    def heapify(self, nums: list[int]):
        n = len(nums)
        for i in range(n - 1, -1, -1):
            self._max_heapify(nums, i, n)

    def _max_heapify(self, nums, index, n):
        largest = index
        left = 2 * index + 1
        right = 2 * index + 2

        if left < n and nums[left] > nums[largest]:
            largest = left

        if right < n and nums[right] > nums[largest]:
            largest = right

        if largest != index:
            nums[index], nums[largest] = nums[largest], nums[index]
            self._max_heapify(nums, largest, n)

