// Solution.cpp
#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    void heapify(vector<int>& nums) {
        int n = nums.size();
        for (int i = n - 1; i >= 0; --i) {
            _max_heapify(nums, i, n);
        }
    }

    void _max_heapify(vector<int>& nums, int index, int n) {
        int largest = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;

        if (left < n && nums[left] > nums[largest]) {
            largest = left;
        }

        if (right < n && nums[right] > nums[largest]) {
            largest = right;
        }

        if (largest != index) {
            swap(nums[index], nums[largest]);
            _max_heapify(nums, largest, n);
        }
    }
};

int main() {
    Solution solution;
    vector<int> nums = {5, 3, 8, 4, 1, 2};
    solution.heapify(nums);
    for (auto num : nums) {
        cout << num << ' ';
    }
    return 0;
}
